// And groups predicates with the AND operator between them.
func And(predicates ...predicate.SalesOrder) predicate.SalesOrder {
	return predicate.SalesOrder(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.SalesOrder) predicate.SalesOrder {
	return predicate.SalesOrder(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.SalesOrder) predicate.SalesOrder {
	return predicate.SalesOrder(sql.NotPredicates(p))
}
